{{- $grafanaDashboards := .Files.Glob "grafana-dashboards/*.json" -}}
{{- range $index, $grafanaDashboard := $grafanaDashboards -}}
{{- with $ }}
apiVersion: v1
kind: ConfigMap
metadata:
{{- $fileName := split "/" $index }}
  name: {{ include "common.names.fullname" . }}-{{ $fileName._1 | trimSuffix ".json" }}-dashboard
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
    {{- with .Values.monitoring.grafana.dashboardLabels }}
    {{- toYaml . | nindent 4 }}
    {{- end }}
  {{- if .Values.monitoring.grafana.dashboardAnnotations }}
  annotations:
    {{- with .Values.monitoring.grafana.dashboardAnnotations}}
    {{- toYaml . | nindent 4 }}
    {{- end }}
  {{- end }}
data:
  {{ include "common.names.fullname" . }}-{{ .Release.Namespace}}-{{ $fileName._1}}: |
{{ .Files.Get $index | indent 4 }}
---
{{- end }}
{{- end }}
{{- end }}

templateSources.bitbucket/templates/httproute.yaml:
{{- if .Values.gateway.create }}
{{- include "common.gateway.validateConfig" . -}}
apiVersion: gateway.networking.k8s.io/v1
kind: HTTPRoute
metadata:
  name: {{ include "common.names.fullname" . }}
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
    {{- with .Values.gateway.labels }}
    {{- toYaml . | nindent 4 }}
    {{- end }}
  {{- with .Values.gateway.annotations }}
  annotations:
    {{- toYaml . | nindent 4 }}
  {{- end }}
spec:
  # Reference to the Gateway
  parentRefs:
  {{- toYaml .Values.gateway.parentRefs | nindent 2 }}

  # Hostnames to match
  hostnames:
  {{- range .Values.gateway.hostnames }}
  - {{ . | quote }}
  {{- end }}

  # Routing rules
  rules:
  # Default rule - routes to Bitbucket service
  - matches:
    - path:
        type: {{ .Values.gateway.pathType }}
        value: {{ include "bitbucket.path" . }}
    {{- with .Values.gateway.timeouts }}
    timeouts:
      {{- toYaml . | nindent 6 }}
    {{- end }}
    {{- with .Values.gateway.filters }}
    filters:
    {{- toYaml . | nindent 4 }}
    {{- end }}
    backendRefs:
    - name: {{ include "common.names.fullname" . }}
      port: {{ .Values.bitbucket.service.port }}
      weight: 100

  {{- with .Values.gateway.additionalRules }}
  {{- toYaml . | nindent 2 }}
  {{- end }}
{{- end }}

templateSources.bitbucket/templates/ingress.yaml:
{{- if and .Values.ingress.create (not .Values.ingress.openShiftRoute) }}
apiVersion: networking.k8s.io/v1
kind: Ingress
metadata:
  name: {{ include "common.names.fullname" . }}
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
  {{ if .Values.ingress.nginx }}
    "nginx.ingress.kubernetes.io/affinity": "cookie"
    "nginx.ingress.kubernetes.io/affinity-mode": "persistent"
    "nginx.ingress.kubernetes.io/proxy-body-size": {{ .Values.ingress.maxBodySize }}
    "nginx.ingress.kubernetes.io/proxy-connect-timeout": {{ .Values.ingress.proxyConnectTimeout|quote }}
    "nginx.ingress.kubernetes.io/proxy-read-timeout": {{ .Values.ingress.proxyReadTimeout|quote }}
    "nginx.ingress.kubernetes.io/proxy-send-timeout": {{ .Values.ingress.proxySendTimeout|quote }}
  {{- end }}
  {{- with .Values.ingress.annotations }}
    {{- toYaml . | nindent 4 }}
  {{- end }}
spec:
{{ if and (.Values.ingress.https) (.Values.ingress.host) }}
  tls:
    - hosts:
        - {{ .Values.ingress.host }}
      {{ if .Values.ingress.tlsSecretName }}
      secretName: {{ .Values.ingress.tlsSecretName }}
      {{ end }}
{{ end }}
  ingressClassName: {{ default "nginx" .Values.ingress.className }}
  rules:
    - host: {{ .Values.ingress.host }}
      http:
        paths:
          - path: {{ include "bitbucket.ingressPath" . }}
            pathType: Prefix
            backend:
              service:
                name: {{ include "common.names.fullname" $ }}
                port:
                  number: {{ $.Values.bitbucket.service.port }}
         {{- range $path := .Values.ingress.additionalPaths }}
          - path: {{ $path.path }}
            pathType: {{ $path.pathType | default "Prefix" }}
            backend:
              service:
                name: {{ $path.service }}
                port:
                  number: {{ $path.portNumber }}
         {{- end }}
{{ end }}

templateSources.bitbucket/templates/job-mesh-add-nodes.y:
{{- if and .Values.bitbucket.sysadminCredentials.secretName .Values.bitbucket.mesh.enabled .Values.bitbucket.mesh.nodeAutoRegistration -}}
{{- range $index := until (.Values.bitbucket.mesh.replicaCount | int) }}
{{- with $ }}
apiVersion: batch/v1
kind: Job
metadata:
  name: {{ include "common.names.fullname" . }}-mesh-register-job-{{ $index }}
  labels:
    app.kubernetes.io/name: {{ include "common.names.name" . }}-mesh-job
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
    "helm.sh/hook": post-install
    "helm.sh/hook-weight": "-10"
    "helm.sh/hook-delete-policy": hook-succeeded
spec:
  template:
    metadata:
      annotations:
        {{- include "bitbucket.mesh.podAnnotations" . | nindent 8 }}
      labels:
        app.kubernetes.io/name: {{ include "common.names.name" . }}-mesh-job
        app.kubernetes.io/instance: {{ .Release.Name }}
        {{- include "bitbucket.mesh.podLabels" . | nindent 8 }}
    spec:
      containers:
        - name: bitbucket-mesh-register-services
          image: curlimages/curl
          command: ["/scripts/register-mesh-node.sh"]
          args: ["{{ $index }}"]
          env:
            {{ with .Values.bitbucket.sysadminCredentials }}
            - name: SYSADMIN_USERNAME
              valueFrom:
                secretKeyRef:
                  name: {{ .secretName }}
                  key: {{ .usernameSecretKey }}
            - name: SYSADMIN_PASSWORD
              valueFrom:
                secretKeyRef:
                  name: {{ .secretName }}
                  key: {{ .passwordSecretKey }}
              {{ end }}
          volumeMounts:
          - name: register-mesh-node
            mountPath: /scripts
      volumes:
      - name: register-mesh-node
        configMap:
          name: {{ include "common.names.fullname" . }}-mesh-scripts
          items:
            - key: register-mesh-node.sh
              path: register-mesh-node.sh
          defaultMode: 0777
      restartPolicy: Never
      {{- with .Values.bitbucket.mesh.nodeSelector }}
      nodeSelector:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.affinity }}
      affinity:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.tolerations }}
      tolerations:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.topologySpreadConstraints }}
      topologySpreadConstraints:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- if .Values.bitbucket.mesh.schedulerName }}
      schedulerName: {{ .Values.bitbucket.mesh.schedulerName  | quote }}
      {{- end }}
  backoffLimit: 4
---
{{- end }}
{{- end }}
{{- end }}

