templateSources.bitbucket/templates/route.yaml:
{{- if and .Values.ingress.create .Values.ingress.openShiftRoute }}
kind: Route
apiVersion: route.openshift.io/v1
metadata:
  name: {{ include "common.names.fullname" . }}
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
    {{- with .Values.ingress.annotations }}
  {{- toYaml . | nindent 4 }}
  {{- end }}
spec:
{{- if .Values.ingress.routeHttpHeaders }}
  httpHeaders:
{{- with .Values.ingress.routeHttpHeaders }}
{{- toYaml . | nindent 4 }}
{{- end }}
{{- end }}
  host: {{ .Values.ingress.host }}
  path: {{ include "bitbucket.ingressPath" . }}
  to:
    kind: Service
    name: {{ include "common.names.fullname" . }}
    weight: 100
  port:
    targetPort: http
{{- if and (.Values.ingress.https) (.Values.ingress.host) }}
  tls:
{{- if .Values.ingress.tlsSecretName }}
{{- $secretData := (lookup "v1" "Secret" .Release.Namespace .Values.ingress.tlsSecretName) }}
{{- if $secretData }}
{{- if hasKey $secretData.data "tls.crt" }}
    certificate: |
      {{- index $secretData.data "tls.crt" | b64dec | nindent 6 }}
{{- end }}
{{- if hasKey $secretData.data "tls.key" }}
    key: |
      {{- index $secretData.data "tls.key" | b64dec | nindent 6 }}
{{- end }}
{{- if hasKey $secretData.data "ca.crt" }}
    caCertificate: |
      {{- index $secretData.data "ca.crt" | b64dec | nindent 6 }}
{{- end }}
{{- end }}
{{- end }}
    termination: edge
    insecureEdgeTerminationPolicy: Redirect
  wildcardPolicy: None
{{- end }}
{{- end }}

templateSources.bitbucket/templates/secret-clustering.ya:
{{/* the default can be removed in v2.0.0 */}}
{{- $clusterGroup := default dict .Values.bitbucket.clustering.group }}
{{- if and .Values.bitbucket.clustering.enabled (empty $clusterGroup.secretName) }}
apiVersion: v1
kind: Secret
metadata:
  name: {{ include "bitbucket.hazelcastGroupSecretName" . | quote }}
  labels:
  {{- include "common.labels.commonLabels" . | nindent 4 }}
type: Opaque
data:
{{- $secretData := (lookup "v1" "Secret" .Release.Namespace (include "bitbucket.hazelcastGroupSecretName" .)) }}
{{- if $secretData.data }}
  # Using existing data
  {{ .Values.bitbucket.clustering.group.nameSecretKey }}: {{ index $secretData.data .Values.bitbucket.clustering.group.nameSecretKey | quote }}
  {{ .Values.bitbucket.clustering.group.passwordSecretKey }}: {{ index $secretData.data .Values.bitbucket.clustering.group.passwordSecretKey | quote }}
{{- else }}
  # Creating new secret
  {{ .Values.bitbucket.clustering.group.nameSecretKey }}: {{ include "common.names.fullname" . | trunc 31 | trimSuffix "-" | b64enc | quote }}
  {{ .Values.bitbucket.clustering.group.passwordSecretKey }}: {{ randAlphaNum 64 | b64enc | quote }}
{{- end }}
{{- end }}

