  labels:
  {{- include "common.labels.commonLabels" . | nindent 4 }}
spec:
  capacity:
    storage: 1Gi
  accessModes:
    - ReadWriteMany
  mountOptions:
  {{- with .Values.volumes.sharedHome.persistentVolume.mountOptions }}
    {{- toYaml . | nindent 4 }}
  {{- else }}
    - rw
    - nfsvers=3
    - lookupcache=pos
    - noatime
    - intr
    - rsize=32768
    - wsize=32768
    - _netdev
  {{- end }}
  {{- with .Values.volumes.sharedHome.persistentVolume.nfs }}
  nfs:
  {{- toYaml . | nindent 4 }}
  {{- end }}
{{ end }}

templateSources.bitbucket/templates/shared-home-pvc.yaml:
{{- if .Values.volumes.sharedHome.persistentVolumeClaim.create }}
apiVersion: v1
kind: PersistentVolumeClaim
metadata:
  name: {{ include "common.names.fullname" . }}-shared-home
  labels:
  {{- include "common.labels.commonLabels" . | nindent 4 }}
spec:
  accessModes:
    - {{ .Values.volumes.sharedHome.persistentVolumeClaim.accessMode }}
  {{- if not (kindIs "invalid" .Values.volumes.sharedHome.persistentVolumeClaim.storageClassName) }}
  storageClassName: {{ .Values.volumes.sharedHome.persistentVolumeClaim.storageClassName | quote }}
  {{- end }}
  {{- if .Values.volumes.sharedHome.persistentVolume.create }}
  volumeName: {{ include "bitbucket.volume.sharedHome.name" . }}
  {{- else if .Values.volumes.sharedHome.persistentVolumeClaim.volumeName }}
  volumeName: {{ .Values.volumes.sharedHome.persistentVolumeClaim.volumeName | quote }}
  {{- end }}
  {{- with .Values.volumes.sharedHome.persistentVolumeClaim.resources }}
  resources:
    {{- toYaml . | nindent 4 }}
  {{- end }}
{{ end }}

templateSources.bitbucket/templates/statefulset-mesh.yam:
{{ if .Values.bitbucket.mesh.enabled }}
apiVersion: apps/v1
kind: StatefulSet
metadata:
  name: {{ include "common.names.fullname" . }}-mesh
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
    {{- with .Values.bitbucket.mesh.additionalAnnotations }}
    {{- toYaml . | nindent 4 }}
    {{- end }}
spec:
  {{- if .Values.updateStrategy }}
  {{- with .Values.updateStrategy }}
  updateStrategy:
  {{- toYaml . | nindent 4 }}
  {{- end }}
  {{- end }}
  {{ if .Values.ordinals.enabled }}
  ordinals:
    start: {{ .Values.ordinals.start }}
  {{ end }}
  replicas: {{ .Values.bitbucket.mesh.replicaCount }}
  podManagementPolicy: {{ default "OrderedReady" .Values.bitbucket.mesh.podManagementPolicy }}
  serviceName: {{ include "common.names.fullname" . }}-mesh
  selector:
    matchLabels:
      app.kubernetes.io/name: {{ include "common.names.name" . }}-mesh
      app.kubernetes.io/instance: {{ .Release.Name }}
  template:
    metadata:
      annotations:
        checksum/config-jvm: {{ include (print $.Template.BasePath "/config-jvm-mesh.yaml") . | sha256sum }}
        {{- if .Values.fluentd.enabled }}
        checksum/config-fluentd: {{ include (print $.Template.BasePath "/configmap-fluentd.yaml") . | sha256sum }}
        {{- end }}
        {{- include "bitbucket.mesh.podAnnotations" . | nindent 8 }}
      labels:
        app.kubernetes.io/name: {{ include "common.names.name" . }}-mesh
        app.kubernetes.io/instance: {{ .Release.Name }}
        {{- include "bitbucket.mesh.podLabels" . | nindent 8 }}
    spec:
      {{- with .Values.bitbucket.mesh.hostNamespaces }}
      {{- toYaml . | nindent 6 }}
      {{- end }}
      serviceAccountName: {{ include "bitbucket.serviceAccountName" . }}
      terminationGracePeriodSeconds: {{ .Values.bitbucket.mesh.shutdown.terminationGracePeriodSeconds }}
      hostAliases:
        {{- include "bitbucket.additionalHosts" . | nindent 8 }}
      initContainers:
        {{- include "bitbucket.mesh.additionalInitContainers" . | nindent 8 }}
        {{- if and .Values.monitoring.exposeJmxMetrics .Values.monitoring.fetchJmxExporterJar }}
        - name: fetch-jmx-exporter
          image: {{ .Values.monitoring.jmxExporterImageRepo}}:{{ .Values.monitoring.jmxExporterImageTag}}
          command: ["cp"]
          args: ["/opt/bitnami/jmx-exporter/jmx_prometheus_javaagent.jar", "{{ .Values.bitbucket.mesh.volume.mountPath }}"]
          volumeMounts:
            - mountPath: {{ .Values.bitbucket.mesh.volume.mountPath | quote }}
              name: mesh-home
          {{- if .Values.openshift.runWithRestrictedSCC }}
          {{- else}}
          {{- if .Values.monitoring.jmxExporterInitContainer.runAsRoot }}
          securityContext:
            runAsUser: 0
          {{- else if .Values.monitoring.jmxExporterInitContainer.customSecurityContext }}
          securityContext:
          {{- with .Values.monitoring.jmxExporterInitContainer.customSecurityContext }}
          {{- toYaml .  | nindent 4 }}
          {{- end }}
          {{- end }}
          {{- end }}
        {{- end }}
        {{- if or .Values.bitbucket.mesh.additionalCertificates.secretName .Values.bitbucket.mesh.additionalCertificates.secretList }}
        - name: import-certs
          image: {{ .Values.bitbucket.mesh.image.repository }}:{{ .Values.bitbucket.mesh.image.tag }}
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          volumeMounts:
            - name: keystore
              mountPath: /var/ssl
          {{- if.Values.bitbucket.mesh.additionalCertificates.secretName }}
            - name: certs
              mountPath: /tmp/crt
          {{- else }}
          {{- range .Values.bitbucket.mesh.additionalCertificates.secretList }}
            {{- $secretName := .name }}
            {{- range .keys }}
            - name: {{ $secretName }}
              mountPath: /tmp/crt/{{$secretName}}-{{ . }}
              subPath: {{ . }}
            {{- end }}
          {{- end }}
          {{- end }}
          command: ["/bin/bash"]
          args: ["-c", {{ include "bitbucketMesh.addCrtToKeystoreCmd" . }}]
          resources:
          {{- with .Values.bitbucket.mesh.additionalCertificates.initContainer.resources }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          securityContext:
          {{- with .Values.bitbucket.mesh.additionalCertificates.initContainer.securityContext }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
        {{- end }}
      containers:
        - name: {{ if .Values.bitbucket.useHelmReleaseNameAsContainerName}}{{ include "common.names.fullname" . }}-mesh{{ else }}{{ .Chart.Name }}-mesh{{ end }}
          image: {{ .Values.bitbucket.mesh.image.repository }}:{{ .Values.bitbucket.mesh.image.tag }}
          imagePullPolicy: {{ .Values.bitbucket.mesh.image.pullPolicy }}
          ports:
            - name: mesh
              containerPort: {{ .Values.bitbucket.mesh.service.port }}
              protocol: TCP
            {{- include "common.jmx.port" . | nindent 12 }}
          readinessProbe:
            tcpSocket:
              port: {{ .Values.bitbucket.mesh.service.port }}
            periodSeconds: 5
            failureThreshold: 60
            initialDelaySeconds: 10
          {{- with .Values.bitbucket.containerSecurityContext}}
          securityContext:
            {{- toYaml . | nindent 12}}
          {{- end}}
          volumeMounts:
            - name: mesh-home
              mountPath: {{ .Values.bitbucket.mesh.volume.mountPath | quote }}
            {{- range $i, $n := .Values.bitbucket.mesh.additionalFiles }}
            - name: {{ .name }}-{{$i}}
              mountPath: {{ .mountPath }}/{{ .key }}
              subPath: {{ .key }}
            {{ end }}
            {{- if or .Values.bitbucket.mesh.additionalCertificates.secretName .Values.bitbucket.mesh.additionalCertificates.secretList }}
            - name: keystore
              mountPath: /var/ssl
            {{- end }}
            {{- include "common.jmx.config.volumeMounts" . | nindent 12 }}
          {{- with .Values.bitbucket.mesh.resources.container }}
          resources:
            {{- toYaml . | nindent 12 }}
          {{- end }}
          env:
            - name: GRPC_SERVER_PORT
              value: {{ .Values.bitbucket.mesh.service.port | quote }}
            - name: MESH_HOME
              value: {{ .Values.bitbucket.mesh.volume.mountPath }}
            - name: KUBE_POD_NAME
              valueFrom:
                fieldRef:
                  fieldPath: metadata.name
            - name: JAVA_OPTS
              value: "-Dcluster.node.name=$(KUBE_POD_NAME)"
            - name: JVM_MINIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: min_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config-mesh
            - name: JVM_MAXIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: max_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config-mesh
            - name: JVM_SUPPORT_RECOMMENDED_ARGS
              valueFrom:
                configMapKeyRef:
                  key: additional_jvm_args
                  name: {{ include "common.names.fullname" . }}-jvm-config-mesh
            {{- if .Values.monitoring.exposeJmxMetrics }}
            - name: JMX_ENABLED
              value: "true"
            {{ end }}
            {{- include "bitbucket.mesh.additionalEnvironmentVariables" . | nindent 12 }}
          lifecycle:
            preStop:
              exec:
                command: ["sh", "-c", {{ .Values.bitbucket.shutdown.command | quote }}]
        {{- include "fluentd.container" . | nindent 8 }}
      {{- with .Values.bitbucket.mesh.nodeSelector }}
      nodeSelector:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.affinity }}
      affinity:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.tolerations }}
      tolerations:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.mesh.topologySpreadConstraints }}
      topologySpreadConstraints:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- if .Values.bitbucket.mesh.schedulerName }}
      schedulerName: {{ .Values.bitbucket.mesh.schedulerName  | quote }}
      {{- end }}
      {{- if .Values.bitbucket.mesh.priorityClassName }}
      priorityClassName: {{ .Values.bitbucket.mesh.priorityClassName }}
      {{- end }}
      volumes:
        {{ include "fluentd.config.volume" . | nindent 8 }}
        {{- range $i, $n := .Values.bitbucket.mesh.additionalFiles }}
        - name: {{ .name }}-{{$i}}
          {{ .type }}:
            {{ if hasPrefix .type "secret" }}{{ .type}}Name{{ else }}name{{ end }}: {{ .name }}
            items:
              - key: {{ .key }}
                path: {{ .key }}
        {{ end }}
        {{- if or .Values.bitbucket.mesh.additionalCertificates.secretName .Values.bitbucket.mesh.additionalCertificates.secretList }}
        - name: keystore
          emptyDir: {}
        {{- if .Values.bitbucket.mesh.additionalCertificates.secretName }}
        - name: certs
          secret:
            secretName: {{ .Values.bitbucket.mesh.additionalCertificates.secretName }}
        {{- else }}
        {{- range .Values.bitbucket.mesh.additionalCertificates.secretList }}
        - name: {{ .name }}
          secret:
            secretName: {{ .name }}
        {{- end }}
        {{- end }}
        {{- end }}
        {{ include "common.jmx.config.volume" . | nindent 8 }}
  {{ include "bitbucket.mesh.volumeClaimTemplates" . | nindent 2 }}
{{ end }}

templateSources.bitbucket/templates/statefulset.yaml:
{{/* This describes a k8s StatefulSet for deploying Bitbucket for testing */}}
{{/* the default can be removed in v2.0.0 */}}
{{- $mirror := default dict .Values.bitbucket.mirror }}
{{- include "common.gateway.validateConfig" . -}}
apiVersion: apps/v1
kind: StatefulSet
metadata:
  name: {{ include "common.names.fullname" . }}
  labels:
    {{- include "common.labels.commonLabels" . | nindent 4 }}
  annotations:
    {{- with .Values.bitbucket.additionalAnnotations }}
    {{- toYaml . | nindent 4 }}
    {{- end }}
spec:
  {{- if .Values.updateStrategy }}
  {{- with .Values.updateStrategy }}
  updateStrategy:
  {{- toYaml . | nindent 4 }}
  {{- end }}
  {{- end }}
  {{ if .Values.ordinals.enabled }}
  ordinals:
    start: {{ .Values.ordinals.start }}
  {{ end }}
  replicas: {{ .Values.replicaCount }}
  podManagementPolicy: {{ default "OrderedReady" .Values.bitbucket.podManagementStrategy }}
  serviceName: {{ include "common.names.fullname" . }}
  selector:
    matchLabels:
      {{- include "common.labels.selectorLabels" . | nindent 6 }}
  template:
    metadata:
      annotations:
        checksum/config-jvm: {{ include (print $.Template.BasePath "/config-jvm.yaml") . | sha256sum }}
        {{- if .Values.additionalConfigMaps }}
        checksum/config-additional: {{ include (print $.Template.BasePath "/configmap-additional-config.yaml") . | sha256sum }}
        {{- end }}
        {{- if .Values.fluentd.enabled }}
        checksum/config-fluentd: {{ include (print $.Template.BasePath "/configmap-fluentd.yaml") . | sha256sum }}
        {{- end }}
        {{- include "bitbucket.podAnnotations" . | nindent 8 }}
      labels:
        {{- include "common.labels.commonLabels" . | nindent 8 }}
        {{- include "bitbucket.podLabels" . | nindent 8 }}
    spec:
      {{- with .Values.hostNamespaces }}
      {{- toYaml . | nindent 6 }}
      {{- end }}
      serviceAccountName: {{ include "bitbucket.serviceAccountName" . }}
      terminationGracePeriodSeconds: {{ .Values.bitbucket.shutdown.terminationGracePeriodSeconds }}
      hostAliases:
        {{- include "bitbucket.additionalHosts" . | nindent 8 }}
      {{- if .Values.openshift.runWithRestrictedSCC }}
      {{- else }}
      {{- if .Values.bitbucket.securityContextEnabled }}
      {{- with .Values.bitbucket.securityContext }}
      securityContext:
        {{ toYaml . | nindent 8 }}
        {{- if not .fsGroup }}
        fsGroup: 2003
        {{- end }}
        {{- end }}
      {{- end }}
      {{- end }}
      initContainers:
        {{- include "bitbucket.additionalInitContainers" . | nindent 8 }}
        {{- if .Values.openshift.runWithRestrictedSCC }}
        {{- else}}
        {{- if and .Values.volumes.sharedHome.nfsPermissionFixer.enabled (or .Values.volumes.sharedHome.persistentVolumeClaim.create .Values.volumes.sharedHome.customVolume) }}
        - name: nfs-permission-fixer
          image: {{ .Values.volumes.sharedHome.nfsPermissionFixer.imageRepo }}:{{ .Values.volumes.sharedHome.nfsPermissionFixer.imageTag }}
          imagePullPolicy: IfNotPresent
          {{- if .Values.volumes.sharedHome.nfsPermissionFixer.resources }}
          resources:
          {{- with .Values.volumes.sharedHome.nfsPermissionFixer.resources }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          {{- end }}
          securityContext:
            runAsUser: 0 # make sure we run as root so we get the ability to change the volume permissions
          volumeMounts:
            - name: shared-home
              mountPath: {{ .Values.volumes.sharedHome.nfsPermissionFixer.mountPath | quote }}
              {{- if .Values.volumes.sharedHome.subPath }}
              subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
              {{- end }}
          command: ["sh", "-c", {{ include "bitbucket.sharedHome.permissionFix.command" . | quote }}]
        {{- end }}
        {{- end }}
        {{- include "common.jmx.initContainer" . | nindent 8 }}
        {{- if or .Values.bitbucket.additionalCertificates.secretName .Values.bitbucket.additionalCertificates.secretList }}
        - name: import-certs
          image: {{ include "bitbucket.image" . | quote }}
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          volumeMounts:
            - name: keystore
              mountPath: /var/ssl
          {{- if.Values.bitbucket.additionalCertificates.secretName }}
            - name: certs
              mountPath: /tmp/crt
          {{- else }}
          {{- range .Values.bitbucket.additionalCertificates.secretList }}
            {{- $secretName := .name }}
            {{- range .keys }}
            - name: {{ $secretName }}
              mountPath: /tmp/crt/{{$secretName}}-{{ . }}
              subPath: {{ . }}
            {{- end }}
          {{- end }}
          {{- end }}
          command: ["/bin/bash"]
          args: ["-c", {{ include "bitbucket.addCrtToKeystoreCmd" . }}]
          resources:
          {{- with .Values.bitbucket.additionalCertificates.initContainer.resources }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          securityContext:
          {{- with .Values.bitbucket.additionalCertificates.initContainer.securityContext }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
        {{- end }}
      containers:
        - name: {{ if .Values.bitbucket.useHelmReleaseNameAsContainerName}}{{ include "common.names.fullname" . }}{{ else }}{{ .Chart.Name }}{{ end }}
          image: {{ include "bitbucket.image" . | quote }}
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          ports:
            - name: http
              containerPort: {{ .Values.bitbucket.ports.http }}
              protocol: TCP
            - name: ssh
              containerPort: {{ .Values.bitbucket.ports.ssh }}
              protocol: TCP
            - name: hazelcast
              containerPort: {{ .Values.bitbucket.ports.hazelcast }}
              protocol: TCP
            {{- include "bitbucket.additionalPorts" . | nindent 12 }}
            {{- include "common.jmx.port" . | nindent 12 }}
          {{- if .Values.bitbucket.readinessProbe.enabled }}
          readinessProbe:
            {{- if .Values.bitbucket.readinessProbe.customProbe}}
            {{- with .Values.bitbucket.readinessProbe.customProbe }}
            {{- toYaml . | nindent 12 }}
            {{- end }}
            {{- else }}
            httpGet:
              port: {{ .Values.bitbucket.ports.http }}
              path: {{ .Values.bitbucket.service.contextPath }}/status
            initialDelaySeconds: {{ .Values.bitbucket.readinessProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.bitbucket.readinessProbe.periodSeconds }}
            timeoutSeconds: {{ .Values.bitbucket.readinessProbe.timeoutSeconds }}
            failureThreshold: {{ .Values.bitbucket.readinessProbe.failureThreshold }}
            {{- end }}
          {{- end }}
          {{- if .Values.bitbucket.startupProbe.enabled }}
          startupProbe:
            tcpSocket:
              port: {{ .Values.bitbucket.ports.http }}
            initialDelaySeconds: {{ .Values.bitbucket.startupProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.bitbucket.startupProbe.periodSeconds }}
            failureThreshold: {{ .Values.bitbucket.startupProbe.failureThreshold }}
          {{- end }}
          {{- if .Values.bitbucket.livenessProbe.enabled }}
          livenessProbe:
          {{- if .Values.bitbucket.livenessProbe.customProbe}}
          {{- with .Values.bitbucket.livenessProbe.customProbe }}
          {{- toYaml . | nindent 12 }}
          {{- end }}
          {{- else }}
            tcpSocket:
              port: {{ .Values.bitbucket.ports.http }}
            initialDelaySeconds: {{ .Values.bitbucket.livenessProbe.initialDelaySeconds }}
            periodSeconds: {{ .Values.bitbucket.livenessProbe.periodSeconds }}
            timeoutSeconds: {{ .Values.bitbucket.livenessProbe.timeoutSeconds }}
            failureThreshold: {{ .Values.bitbucket.livenessProbe.failureThreshold }}
          {{- end }}
          {{- end }}
          {{- with .Values.bitbucket.containerSecurityContext}}
          securityContext:
            {{- toYaml . | nindent 12}}
          {{- end}}
          volumeMounts:
            - name: local-home
              mountPath: {{ .Values.volumes.localHome.mountPath | quote }}
              {{- if .Values.volumes.localHome.subPath }}
              subPath: {{ .Values.volumes.localHome.subPath | quote }}
              {{- end }}
            {{/* jmxExporter is saved to shared home but mirrors don't have one, so we need at least emptyDir */}}
            {{- if or .Values.volumes.sharedHome.persistentVolumeClaim.create .Values.volumes.sharedHome.customVolume
               (and (eq .Values.bitbucket.applicationMode "mirror") .Values.monitoring.exposeJmxMetrics) }}
            - name: shared-home
              mountPath: {{ .Values.volumes.sharedHome.mountPath | quote }}
              {{- if .Values.volumes.sharedHome.subPath }}
              subPath: {{ .Values.volumes.sharedHome.subPath | quote }}
              {{- end }}
            {{- end }}
            {{- if or .Values.bitbucket.additionalCertificates.secretName .Values.bitbucket.additionalCertificates.secretList }}
            - name: keystore
              mountPath: /var/ssl
            {{- end }}
            {{- if or .Values.atlassianAnalyticsAndSupport.analytics.enabled .Values.atlassianAnalyticsAndSupport.helmValues.enabled }}
            - name: helm-values
              mountPath: /opt/atlassian/helm
            {{- end }}
            {{- include "bitbucket.additionalVolumeMounts" . | nindent 12 }}
            {{- include "common.jmx.config.volumeMounts" . | nindent 12 }}
            {{- include "bitbucket.additionalLibraries" . | nindent 12 }}
            {{- include "bitbucket.additionalBundledPlugins" . | nindent 12 }}
            {{- range $i, $n := .Values.additionalFiles }}
            - name: {{ .name }}-{{$i}}
              mountPath: {{ .mountPath }}/{{ .key }}
              subPath: {{ .key }}
            {{ end }}
            {{- range $i, $n := .Values.additionalConfigMaps }}
            {{- range .keys }}
            - name: {{ .fileName | replace "_" "-" | replace "." "-" }}
              mountPath: {{ .mountPath }}/{{ .fileName }}
              subPath: {{ .fileName }}
            {{ end }}
            {{- end }}
          {{- with .Values.bitbucket.resources.container }}
          resources:
            {{- toYaml . | nindent 12 }}
          {{- end }}
          env:
            - name: KUBE_POD_NAME
              valueFrom:
                fieldRef:
                  fieldPath: metadata.name
            - name: JAVA_OPTS
              value: "-Dcluster.node.name=$(KUBE_POD_NAME)"
            {{- include "bitbucket.clusteringEnvVars" . | nindent 12 }}
            {{- include "bitbucket.databaseEnvVars" . | nindent 12 }}
            {{- include "bitbucket.sysadminEnvVars" . | nindent 12 }}
            {{- if .Values.bitbucket.elasticSearch.baseUrl }}
            {{- include "bitbucket.elasticSearchEnvVars" . | nindent 12 }}
            {{- else }}
            {{- include "bitbucket.openSearchEnvVars" . | nindent 12 }}
            {{- end }}
            - name: PLUGIN_SSH_PORT
              value: {{ .Values.bitbucket.ports.ssh | quote }}
            {{ if eq (include "common.gateway.isConfigured" .) "true" }}
            - name: SERVER_PROXY_NAME
              value: {{ include "common.gateway.hostname" . | quote }}
            - name: SERVER_PROXY_PORT
              value: {{ include "common.gateway.externalPort" . | quote }}
            - name: SETUP_BASEURL
              value: {{ include "common.gateway.origin" . | quote }}
            {{- with .Values.bitbucket.displayName }}
            - name: SETUP_DISPLAYNAME
              value: {{ . | quote }}
            {{- end }}
            {{- if and .Values.bitbucket.sshService.enabled (not (empty .Values.bitbucket.sshService.host)) }}
            - name: PLUGIN_SSH_BASEURL
              value: ssh://{{ .Values.bitbucket.sshService.host }}{{ if ne (int .Values.bitbucket.sshService.port) 22 }}:{{ .Values.bitbucket.sshService.port }}{{ end }}/
            {{- end }}
            {{ end }}
            - name: SERVER_CONTEXT_PATH
              value: {{ include "bitbucket.path" . | quote }}
            - name: SERVER_PORT
              value: {{ .Values.bitbucket.ports.http | quote }}
            {{ if eq (include "common.gateway.https" .) "true" }}
            - name: SERVER_SCHEME
              value: "https"
            - name: SERVER_SECURE
              value: "true"
            {{ end }}
            - name: SET_PERMISSIONS
              value: {{ .Values.bitbucket.setPermissions | quote }}
            {{- if or .Values.volumes.sharedHome.persistentVolumeClaim.create .Values.volumes.sharedHome.customVolume }}
            - name: BITBUCKET_SHARED_HOME
              value: {{ .Values.volumes.sharedHome.mountPath | quote }}
            {{- end }}
            {{ with .Values.bitbucket.license.secretName }}
            - name: SETUP_LICENSE
              valueFrom:
                secretKeyRef:
                  name: {{ . }}
                  key: {{ $.Values.bitbucket.license.secretKey }}
            {{ end }}
            {{- with $mirror.upstreamUrl }}
            - name: PLUGIN_MIRRORING_UPSTREAM_URL
              value: {{ . | quote }}
            - name: PLUGIN_MIRRORING_UPSTREAM_TYPE
              value: "server"
            {{- end }}
            - name: JVM_MINIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: min_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: JVM_MAXIMUM_MEMORY
              valueFrom:
                configMapKeyRef:
                  key: max_heap
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: JVM_SUPPORT_RECOMMENDED_ARGS
              valueFrom:
                configMapKeyRef:
                  key: additional_jvm_args
                  name: {{ include "common.names.fullname" . }}-jvm-config
            - name: APPLICATION_MODE
              value: {{ .Values.bitbucket.applicationMode | default "default" | quote }}
            {{- if .Values.monitoring.exposeJmxMetrics }}
            - name: JMX_ENABLED
              value: "true"
            {{ end }}
            {{- include "bitbucket.additionalEnvironmentVariables" . | nindent 12 }}
          lifecycle:
          {{- if .Values.bitbucket.postStart.command }}
            postStart:
              exec:
                command: ["/bin/sh", "-c", {{- .Values.bitbucket.postStart.command | quote }}]
          {{- end }}
            preStop:
              exec:
                command: ["sh", "-c", {{ .Values.bitbucket.shutdown.command | quote }}]
        {{- include "fluentd.container" . | nindent 8 }}
        {{- include "bitbucket.additionalContainers" . | nindent 8 }}
      {{- with .Values.nodeSelector }}
      nodeSelector:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.affinity }}
      affinity:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.tolerations }}
      tolerations:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with .Values.bitbucket.topologySpreadConstraints }}
      topologySpreadConstraints:
      {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- if .Values.schedulerName }}
      schedulerName: {{ .Values.schedulerName  | quote }}
      {{- end }}
      {{- if .Values.priorityClassName }}
      priorityClassName: {{ .Values.priorityClassName }}
      {{- end }}
      volumes:
        {{- range $i, $n := .Values.additionalFiles }}
        - name: {{ .name }}-{{$i}}
          {{ .type }}:
            {{ if hasPrefix .type "secret" }}{{ .type}}Name{{ else }}name{{ end }}: {{ .name }}
            items:
              - key: {{ .key }}
                path: {{ .key }}
        {{ end }}
        {{- range $i, $key := .Values.additionalConfigMaps }}
        {{- with $ }}
        {{- range $key.keys }}
        - name: {{ .fileName | replace "_" "-" | replace "." "-" }}
          configMap:
            name: {{ include "common.names.fullname" $ }}-{{ $key.name }}
            {{- if .defaultMode }}
            defaultMode: {{ .defaultMode }}
            {{- end }}
            items:
              - key: {{ .fileName }}
                path: {{ .fileName }}
            {{- end }}
        {{ end }}
        {{- end }}
        {{ include "bitbucket.volumes" . | nindent 8 }}
        {{ include "fluentd.config.volume" . | nindent 8 }}
        {{ include "common.jmx.config.volume" . | nindent 8 }}
  {{ include "bitbucket.volumeClaimTemplates" . | nindent 2 }}

